questionvariables.text:
/* ===== Parameter set selection ===== */
set: rand(4)+1;

/* ===== Given values ===== */
Z0: if set=1 then 50 else if set=2 then 75 else if set=3 then 100 else 50;
ZL: if set=1 then 100 else if set=2 then 200 else if set=3 then 25 else 150;
f_GHz: if set=1 then 2 else if set=2 then 1 else if set=3 then 5 else 2;
eps_r: if set=1 then 2.25 else if set=2 then 1 else if set=3 then 4 else 2.25;

c0: 3e8;
f_Hz: float(f_GHz * 1e9);
vp: float(c0 / sqrt(eps_r));

/* ===== Teacher answers ===== */

/* (a) QWT characteristic impedance */
ta1: float(sqrt(Z0 * ZL));

/* (b) Physical length in metres */
ta2: float(vp / (4 * f_Hz));

/* (c) Electrical length in degrees */
ta3: 90;

/* (d) |Γ| at design frequency — exactly 0 */
ta4: 0;

/* (e) MCQ: still matched at 1.1f? — No */
ta5: random_permutation([[1, false, "Yes"], [2, true, "No"]]);
ta5_correct: 2;

/* ===== Off-frequency analysis ===== */
f_new: float(1.1 * f_Hz);
f_new_GHz: float(1.1 * f_GHz);
beta_new: float(2 * %pi * f_new / vp);
l_qwt: ta2;
theta_new: float(beta_new * l_qwt);

/* Z_in at shifted frequency */
tan_theta: float(tan(theta_new));
Z_in_num: float(rectform(ZL + %i * ta1 * tan_theta));
Z_in_den: float(rectform(ta1 + %i * ZL * tan_theta));
Z_in: float(rectform(Z_in_num / Z_in_den));

/* Gamma at shifted frequency */
Gamma_shifted: float(rectform((Z_in - Z0) / (Z_in + Z0)));

/* (f) |Γ| at shifted frequency */
ta6: float(cabs(Gamma_shifted));

/* (g) Reflected power fraction */
ta7: float(ta6^2);
